def load_recommendation_feedback_context_for_chat(dialog_id: str, target_date: date) -> dict[str, Any]:
    if not postgres_enabled():
        return {"recommendations": [], "events": []}
    previous_date = target_date - timedelta(days=1)
    with pg_connect() as conn:
        with conn.cursor() as cur:
            cur.execute("SELECT id, dialog_id, chat_title FROM chats WHERE dialog_id = %s", (dialog_id,))
            chat = cur.fetchone()
            if not chat:
                return {"recommendations": [], "events": []}
            chat_id = chat["id"]
            cur.execute(
                """
                SELECT user_id
                FROM chat_members
                WHERE chat_id = %s AND is_active = TRUE
                """,
                (chat_id,),
            )
            member_ids = [row["user_id"] for row in cur.fetchall()]
            member_filter = "FALSE"
            if member_ids:
                member_filter = "(r.manager_user_id = ANY(%s::uuid[]) OR r.employee_user_id = ANY(%s::uuid[]))"
                member_uuid_texts = [str(item) for item in member_ids]
            cur.execute(
                f"""
                SELECT
                    r.id, r.status, r.priority, r.recommendation_type, r.subject,
                    r.recommendation_text, r.expected_action, r.due_date,
                    r.response_due_at, r.execution_due_at, r.sent_at, r.last_response_at,
                    r.manager_review_required, r.current_interpretation,
                    mu.full_name AS manager_name,
                    eu.full_name AS employee_name,
                    sc.dialog_id AS source_dialog_id,
                    sc.chat_title AS source_chat_title,
                    fc.dialog_id AS feedback_dialog_id,
                    fc.chat_title AS feedback_chat_title
                FROM owner_manager_recommendations r
                LEFT JOIN users mu ON mu.id = r.manager_user_id
                LEFT JOIN users eu ON eu.id = r.employee_user_id
                LEFT JOIN chats sc ON sc.id = r.source_chat_id
                LEFT JOIN chats fc ON fc.id = r.feedback_chat_id
                WHERE (
                    r.source_chat_id = %s
                    OR r.feedback_chat_id = %s
                    OR COALESCE(r.feedback_dialog_id, '') = %s
                    OR {member_filter}
                )
                  AND (
                    r.status = ANY(%s::text[])
                    OR r.created_at::date BETWEEN %s AND %s
                    OR r.sent_at::date BETWEEN %s AND %s
                    OR r.last_response_at::date BETWEEN %s AND %s
                  )
                ORDER BY r.manager_review_required DESC, r.last_response_at DESC NULLS LAST, r.created_at DESC
                LIMIT 80
                """,
                [
                    chat_id,
                    chat_id,
                    dialog_id,
                    *([] if not member_ids else [member_uuid_texts, member_uuid_texts]),
                    list(OPEN_RECOMMENDATION_STATUSES),
                    previous_date,
                    target_date,
                    previous_date,
                    target_date,
                    previous_date,
                    target_date,
                ],
            )
            recommendations = cur.fetchall()
            events: list[dict[str, Any]] = []
            if recommendations:
                recommendation_ids = [str(row["id"]) for row in recommendations]
                cur.execute(
                    """
                    SELECT
                        e.recommendation_id, e.event_type, e.author_type,
                        e.author_bitrix_user_id, u.full_name AS author_name,
                        e.dialog_id, c.chat_title, e.bitrix_message_id,
                        e.chat_message_day, e.old_status, e.new_status,
                        e.event_text, e.interpretation, e.source_payload, e.event_at
                    FROM owner_recommendation_events e
                    LEFT JOIN users u ON u.id = e.author_user_id
                    LEFT JOIN chats c ON c.id = e.chat_id
                    WHERE e.recommendation_id = ANY(%s::uuid[])
                    ORDER BY e.event_at DESC
                    LIMIT 300
                    """,
                    (recommendation_ids,),
                )
                events = cur.fetchall()
    return {
        "period_checked": {"date_from": previous_date.isoformat(), "date_to": target_date.isoformat()},
        "chat": {"dialog_id": dialog_id, "chat_title": chat.get("chat_title") if chat else None},
        "recommendations": recommendations,
        "events": events,
        "rule": (
            "Проверь переписку предыдущего и текущего дня по этим рекомендациям. "
            "Неясные, уклончивые или противоречивые ответы верни в strange_feedback с label='Странная обратная связь'."
        ),
    }


def format_recommendation_feedback_context_for_prompt(context: dict[str, Any], max_chars: int = 20000) -> str:
    recommendations = context.get("recommendations") if isinstance(context, dict) else []
    events = context.get("events") if isinstance(context, dict) else []
    if not recommendations:
        return "Активных рекомендаций для проверки по этому чату не найдено."
    payload = {
        "period_checked": context.get("period_checked"),
        "recommendations": recommendations,
        "events": events,
        "rule": context.get("rule"),
    }
    text = json.dumps(payload, ensure_ascii=False, indent=2, default=str)
    return text[:max_chars]


def save_recommendation_feedback_from_chat_analysis(
    cur: Any,
    chat_id: Any,
    dialog_id: str,
    report_date: date,
    report_id: Any,
    analysis: dict[str, Any],
) -> None:
    status_values = {
        "accepted",
        "in_progress",
        "needs_clarification",
        "disagreed",
        "delegated",
        "done",
        "no_response",
        "overdue",
        "requires_manager_review",
    }

    def evidence_ids(item: dict[str, Any]) -> list[int]:
        raw = item.get("evidence_message_ids")
        if not isinstance(raw, list):
            return []
        values: list[int] = []
        for value in raw:
            parsed = to_int(value)
            if parsed is not None:
                values.append(parsed)
        return values

    def insert_event(item: dict[str, Any], event_type: str, status_key: str, label: str) -> None:
        recommendation_id = str(item.get("recommendation_id") or "").strip()
        if not recommendation_id:
            return
        try:
            recommendation_uuid = UUID(recommendation_id)
        except (TypeError, ValueError):
            return
        cur.execute("SELECT id, status FROM owner_manager_recommendations WHERE id = %s", (recommendation_uuid,))
        row = cur.fetchone()
        if not row:
            return
        old_status = str(row.get("status") or "new")
        new_status = str(item.get(status_key) or "").strip()
        if new_status not in status_values:
            new_status = "requires_manager_review" if event_type == "ai_interpreted" else old_status
        review_required = bool(item.get("requires_manager_review")) or new_status == "requires_manager_review"
        text = str(item.get("summary") or item.get("reason") or item.get("raw_answer_summary") or label).strip()
        ids = evidence_ids(item)
        source_payload = {
            "source": "chat_daily_report",
            "report_id": str(report_id),
            "report_date": report_date.isoformat(),
            "dialog_id": dialog_id,
            "evidence_message_ids": ids,
            "label": label,
        }
        cur.execute(
            """
            INSERT INTO owner_recommendation_events (
                recommendation_id, event_type, author_type, chat_id, dialog_id,
                old_status, new_status, event_text, interpretation, source_payload,
                chat_message_day
            )
            VALUES (%s, %s, 'ai', %s, %s, %s, %s, %s, %s, %s, %s)
            """,
            (
                recommendation_uuid,
                event_type,
                chat_id,
                dialog_id,
                old_status,
                new_status,
                text,
                pg_json(item),
                pg_json(source_payload),
                report_date,
            ),
        )
        cur.execute(
            """
            UPDATE owner_manager_recommendations
            SET status = %s,
                feedback_chat_id = COALESCE(feedback_chat_id, %s),
                feedback_dialog_id = COALESCE(feedback_dialog_id, %s),
                current_interpretation = %s,
                manager_review_required = manager_review_required OR %s,
                last_response_at = CASE
                    WHEN %s = ANY(ARRAY['accepted','in_progress','needs_clarification','disagreed','delegated','done','requires_manager_review'])
                    THEN now()
                    ELSE last_response_at
                END,
                closed_at = CASE WHEN %s IN ('done','rejected') THEN COALESCE(closed_at, now()) ELSE closed_at END,
                updated_at = now()
            WHERE id = %s
            """,
            (
                new_status,
                chat_id,
                dialog_id,
                pg_json(item),
                review_required,
                new_status,
                new_status,
                recommendation_uuid,
            ),
        )

    for item in analysis.get("recommendation_feedback") or []:
        if isinstance(item, dict):
            insert_event(item, "ai_interpreted", "understood_status", "Обратная связь по рекомендации")
    for item in analysis.get("strange_feedback") or []:
        if isinstance(item, dict):
            insert_event(item, "ai_interpreted", "recommended_status", "Странная обратная связь")


def generate_ai_chat_report(dialog_id: str, target_date: date, force: bool = False) -> dict[str, Any]:
    raise ValueError("Ежедневные отчеты по чатам отключены. Подтягиваются только переписки чатов и OCR.")
    finalization_error = chat_day_finalization_error(target_date)
    if finalization_error:
        raise ValueError(finalization_error)
    if target_date > REPORT_PLACEHOLDER_START_DATE:
        previous_date = target_date - timedelta(days=1)
        previous_report = load_chat_day(dialog_id, previous_date).get("report")
        if chat_day_has_messages(dialog_id, previous_date) and not is_completed_chat_day_report(previous_report):
            raise ValueError(
                "Нельзя сформировать отчет за эту дату, пока не сформирован отчет за предыдущий день. "
                f"Сначала сформируйте отчет за {format_date_ru(previous_date)}."
            )
    chat_day = load_chat_day(dialog_id, target_date)
    if not (chat_day.get("messages") or []):
        return chat_day | {
            "skipped": True,
            "message": "В чате нет сообщений за дату; ежедневный отчет не создан.",
        }
    if is_real_ai_chat_report(chat_day.get("report")) and not force:
        return chat_day
    text_status = chat_day.get("text_status") or {}
    if not text_status.get("is_processed"):
        process_chat_image_ocr_for_period(target_date, target_date, force=False, dialog_id=dialog_id)
        chat_day = load_chat_day(dialog_id, target_date)
        text_status = chat_day.get("text_status") or {}
        if not text_status.get("is_processed"):
            raise ValueError(
                "Чат еще не обработан: OCR изображений не завершен. "
                f"Статус: {text_status.get('status_text') or 'Не обработан'}."
            )

    api_key = llm_api_key()
    model = os.getenv("OPENAI_MODEL", "gpt-4.1-mini").strip()
    transcript = chat_day["transcript"]
    previous_date = target_date - timedelta(days=1)
    previous_chat_day = load_chat_day(dialog_id, previous_date)
    previous_transcript = str(previous_chat_day.get("transcript") or "Нет сообщений")
    previous_day_tasks = load_previous_chat_tail_tasks(dialog_id, target_date)
    previous_day_tasks_for_prompt = compact_previous_chat_tail_tasks_for_prompt(previous_day_tasks, max_items=60, max_chars=24000)
    previous_day_tasks_text = format_previous_chat_tail_tasks_for_prompt(previous_day_tasks_for_prompt)
    previous_day_report_payload = compact_previous_chat_daily_report_for_prompt(dialog_id, target_date)
    previous_day_report_text = format_previous_chat_daily_report_for_prompt(previous_day_report_payload)
    recommendation_feedback_context = load_recommendation_feedback_context_for_chat(dialog_id, target_date)
    recommendation_feedback_text = format_recommendation_feedback_context_for_prompt(recommendation_feedback_context)
    previous_week_report = load_previous_chat_weekly_context(dialog_id, target_date)
    previous_week_text = compact_previous_week_report_for_prompt(previous_week_report, max_chars=5000)
    previous_week_payload = compact_previous_week_report_for_payload(previous_week_report)
    zoom_calls_for_prompt = load_zoom_calls_for_chat_prompt(target_date)
    zoom_calls_text = format_zoom_calls_for_chat_prompt(zoom_calls_for_prompt)
    if not api_key:
        raise ValueError("Для ИИ-отчета по чату укажите OPENAI_API_KEY или GOOGLE_API_KEY в .env")
    previous_transcript_for_ai = previous_transcript[:30000]
    transcript_for_ai = transcript[:50000]
    prompt_id = None
    base_prompt = DEFAULT_CHAT_ANALYSIS_PROMPT
    if postgres_enabled():
        with pg_connect() as conn:
            with conn.cursor() as cur:
                prompt_id, configured_prompt = pg_active_prompt(cur, "chat_analysis", DEFAULT_CHAT_ANALYSIS_PROMPT)
                base_prompt = configured_prompt or DEFAULT_CHAT_ANALYSIS_PROMPT
    prompt = (
        base_prompt.strip()
        + "\n\n"
        + "Контекст анализа:\n"
        f"Дата: {target_date.isoformat()}\n"
        f"Чат: {(chat_day.get('chat') or {}).get('title') or dialog_id}\n\n"
        f"Переписка предыдущего дня ({previous_date.isoformat()}):\n{previous_transcript_for_ai}\n\n"
        f"Хвосты с прошлого дня:\n{previous_day_tasks_text}\n\n"
        f"Отчет предыдущего дня:\n{previous_day_report_text}\n\n"
        f"Адресные рекомендации и обратная связь:\n{recommendation_feedback_text}\n\n"
        f"Недельный контекст предыдущей недели:\n{previous_week_text}\n\n"
        f"Zoom-отчеты текущего дня:\n{zoom_calls_text}\n\n"
        f"Расшифровка:\n{transcript_for_ai}"
    )
    message_order = [
        {
            "sequence_no": item.get("sequence_no"),
            "message_id": item.get("message_id"),
            "message_date": item.get("message_date"),
            "author_id": item.get("author_id"),
            "author_name": item.get("author_name"),
            "attachments": [
                {
                    "file_id": file_item.get("file_id"),
                    "file_name": file_item.get("name") or file_item.get("file_name"),
                    "file_type": file_item.get("type") or file_item.get("file_type"),
                    "ocr_status": file_item.get("ocr_status"),
                    "has_ocr_text": bool(file_item.get("ocr_text")),
                }
                for file_item in (item.get("files") or [])
            ],
        }
        for item in (chat_day.get("messages") or [])
    ]
    started_at = datetime.now()
    ai_request_id = None
    raw: dict[str, Any] | None = None
    if postgres_enabled():
        with pg_connect() as conn:
            with conn.cursor() as cur:
                ai_request_id = pg_insert_ai_request(
                    cur,
                    "chat_daily_analysis",
                    prompt_id,
                    prompt,
                    "openai",
                    model,
                    {
                        "dialog_id": dialog_id,
                        "chat": chat_day.get("chat"),
                        "report_date": target_date.isoformat(),
                        "transcript_format": "ordered_message_blocks_v2",
                        "messages_count": len(chat_day.get("messages") or []),
                        "message_order": message_order,
                        "previous_day_tasks": previous_day_tasks_for_prompt,
                        "previous_day_tasks_total": len(previous_day_tasks),
                        "previous_day_tasks_used": len(previous_day_tasks_for_prompt),
                        "previous_day_report": previous_day_report_payload,
                        "previous_transcript": previous_transcript_for_ai,
                        "previous_transcript_truncated": len(previous_transcript) > len(previous_transcript_for_ai),
                        "recommendation_feedback_context": recommendation_feedback_context,
                        "previous_week_report": previous_week_payload,
                        "zoom_calls": zoom_calls_for_prompt,
                        "zoom_calls_count": len(zoom_calls_for_prompt),
                        "zoom_source_type": "standalone_zoom_reports_analytical_note",
                        "zoom_raw_transcripts_included": False,
                        "transcript": transcript_for_ai,
                        "transcript_truncated": len(transcript) > len(transcript_for_ai),
                    },
                    started_at,
                )

    try:
        response = llm_post_with_retry(
            llm_api_url("/chat/completions"),
            headers=llm_auth_headers(api_key),
            payload={
                "model": model,
                "messages": [
                    {"role": "system", "content": "Ты аналитик операционной команды. Возвращай только валидный JSON по запрошенной схеме."},
                    {"role": "user", "content": prompt},
                ],
                "temperature": 0.2,
                "response_format": {"type": "json_object"},
            },
            timeout=max(180, int(os.getenv("OPENAI_TIMEOUT_SECONDS", "180"))),
        )
        response.raise_for_status()
        raw = response.json()
        content = raw["choices"][0]["message"]["content"]
        analysis = extract_json_object(content)
        analysis["previous_day_tasks"] = merge_unseen_previous_day_tasks(
            previous_day_tasks,
            analysis.get("previous_day_tasks"),
        )
    except Exception as exc:  # noqa: BLE001
        if postgres_enabled() and ai_request_id:
            with pg_connect() as conn:
                with conn.transaction():
                    with conn.cursor() as cur:
                        pg_finish_ai_request(
                            cur,
                            ai_request_id,
                            "error",
                            started_at,
                            raw_response_json=raw if isinstance(raw, dict) else {"error": str(exc)},
                            error_text=str(exc),
                        )
        raise

    if postgres_enabled() and ai_request_id:
        with pg_connect() as conn:
            with conn.transaction():
                with conn.cursor() as cur:
                    pg_finish_ai_request(
                        cur,
                        ai_request_id,
                        "success",
                        started_at,
                        response_text=content,
                        response_json=analysis,
                        raw_response_json=raw,
                    )
    report_text = structured_chat_report_text(analysis)
    save_chat_daily_report(
        dialog_id,
        target_date,
        report_text,
        model,
        {
            "source": "chat_structured_report",
            "model": model,
            "analysis": analysis,
            "raw_response": raw,
            "ai_request_id": str(ai_request_id) if ai_request_id else None,
            "transcript_format": "ordered_message_blocks_v2",
            "previous_day_tasks_input": previous_day_tasks,
            "previous_day_report_input": previous_day_report_payload,
            "previous_transcript_input_truncated": len(previous_transcript) > len(previous_transcript_for_ai),
            "recommendation_feedback_context_input": recommendation_feedback_context,
            "zoom_calls_input": zoom_calls_for_prompt,
            "zoom_source_type": "standalone_zoom_reports_analytical_note",
            "zoom_raw_transcripts_included": False,
        },
        ai_request_id=ai_request_id,
        prompt_id=prompt_id,
    )

    return load_chat_day(dialog_id, target_date)


app = Flask(__name__)
app.config["SECRET_KEY"] = os.getenv("FLASK_SECRET_KEY", "change-this-secret")
app.config["PERMANENT_SESSION_LIFETIME"] = timedelta(days=int(os.getenv("AUTH_SESSION_DAYS", "30") or "30"))
app.config["SESSION_COOKIE_HTTPONLY"] = True
app.config["SESSION_COOKIE_SAMESITE"] = os.getenv("SESSION_COOKIE_SAMESITE", "Lax")
session_cookie_secure_default = "1" if os.getenv("CANONICAL_WEB_HOST", "").strip() else "0"
app.config["SESSION_COOKIE_SECURE"] = os.getenv("SESSION_COOKIE_SECURE", session_cookie_secure_default).strip().lower() not in {"0", "false", "no"}
app.jinja_env.filters["dt_ru"] = format_datetime_ru
if app.config["SECRET_KEY"] == "change-this-secret":
    app.logger.warning("FLASK_SECRET_KEY is not configured; session signing uses the insecure development fallback.")
if os.getenv("MCP_ALLOW_UNAUTHENTICATED", "").strip() == "1":
    app.logger.warning("MCP_ALLOW_UNAUTHENTICATED=1 is enabled; MCP endpoints are open without a shared secret.")
if not postgres_enabled():
    init_db()
    repair_db_chat_columns()
    repair_db_status_labels()
    repair_db_checklist_counts()


@app.errorhandler(HTTPException)
def handle_http_exception(exc: HTTPException):
    if wants_json_response():
        return error_response(exc.description or exc.name, exc.code or 500, exc.name.lower().replace(" ", "_"))
    return exc


@app.errorhandler(Exception)
def handle_unhandled_exception(exc: Exception):
    request_id = uuid4().hex
    app.logger.exception("Unhandled request error request_id=%s path=%s", request_id, request.path)
    if wants_json_response() or request.path.startswith(("/mcp", "/mcp-faq", "/sse")):
        return error_response("Internal server error.", 500, "internal_server_error", request_id=request_id)
    return Response("Internal server error.", status=500, mimetype="text/plain")


MCP_SSE_SESSIONS: dict[str, Queue[str]] = {}
LOGIN_ATTEMPTS: dict[str, list[float]] = {}
AUTH_EXEMPT_PREFIXES = (
    "/login",
    "/logout",
    "/assets/",
    "/favicon",
    "/mcp",
    "/mcp-faq",
    "/sse",
    "/sse-faq",
    "/bitrix/events/",
    "/bitrix/imbot/",
    "/zoom/events/",
    "/google-drive/events/",
    "/zoom-export/",
)


def configured_admin_password_hash() -> str:
    return os.getenv("ADMIN_PASSWORD_HASH", "").strip()


def request_client_ip() -> str:
    real_ip = request.headers.get("X-Real-IP", "").strip()
    if real_ip:
        return real_ip
    forwarded = request.headers.get("X-Forwarded-For", "")
    if forwarded:
        return forwarded.rsplit(",", 1)[-1].strip() or request.remote_addr or "unknown"
    return request.remote_addr or "unknown"


def login_rate_limited(client_ip: str) -> bool:
    window_seconds = int(os.getenv("AUTH_RATE_LIMIT_WINDOW_SECONDS", "900") or "900")
    max_attempts = int(os.getenv("AUTH_RATE_LIMIT_ATTEMPTS", "6") or "6")
    now = time.time()
    attempts = [ts for ts in LOGIN_ATTEMPTS.get(client_ip, []) if now - ts < window_seconds]
    LOGIN_ATTEMPTS[client_ip] = attempts
    return len(attempts) >= max_attempts


def record_failed_login(client_ip: str) -> None:
    LOGIN_ATTEMPTS.setdefault(client_ip, []).append(time.time())


def clear_failed_logins(client_ip: str) -> None:
    LOGIN_ATTEMPTS.pop(client_ip, None)


def authenticated() -> bool:
    return bool(session.get("admin_authenticated"))


def auth_exempt_path(path: str) -> bool:
    return any(path == prefix.rstrip("/") or path.startswith(prefix) for prefix in AUTH_EXEMPT_PREFIXES)


def internal_api_auth_ok() -> bool:
    expected = os.getenv("MCP_SHARED_SECRET", "").strip()
    if not expected:
        return False
    provided = first_non_empty(
        request.headers.get("X-MCP-Shared-Secret"),
        request.headers.get("X-Internal-Secret"),
    )
    return hmac.compare_digest(str(provided or "").strip(), expected)


def wants_json_response() -> bool:
    return request.path.startswith("/api/") or "application/json" in request.headers.get("Accept", "")


def legacy_http_api_enabled() -> bool:
    return os.getenv("ALLOW_LEGACY_HTTP_API", "").strip() == "1"


def error_response(message: str, status_code: int = 400, code: str = "error", *, request_id: str | None = None):
    payload = {"error": {"code": code, "message": message}}
    if request_id:
        payload["error"]["request_id"] = request_id
    return jsonify(payload), status_code


def browser_origin_ok() -> bool:
    scheme = request.headers.get("X-Forwarded-Proto", "").split(",", 1)[0].strip() or request.scheme
    expected_origin = f"{scheme}://{request.host}"
    origin = request.headers.get("Origin", "").strip()
    if origin:
        return origin == expected_origin
    referer = request.headers.get("Referer", "").strip()
    if referer:
        return referer.startswith(f"{expected_origin}/")
    return True


def canonical_web_redirect():
    canonical_host = os.getenv("CANONICAL_WEB_HOST", "").strip().lower()
    if not canonical_host:
        return None

    mcp_host = os.getenv("MCP_HOST", "").strip().lower()
    current_host = request.host.split(":", 1)[0].lower()
    if current_host in {canonical_host, mcp_host}:
        return None
    if request.path.startswith(("/mcp", "/mcp-faq", "/sse", "/sse-faq", "/bitrix/events/", "/bitrix/imbot/", "/zoom/events/", "/google-drive/events/")) and mcp_host:
        target_host = mcp_host
    else:
        target_host = canonical_host
    return redirect(f"https://{target_host}{request.full_path.rstrip('?')}", code=301)


@app.before_request
def require_admin_auth():
    redirect_response = canonical_web_redirect()
    if redirect_response is not None:
        return redirect_response

    path = request.path
    if path == "/":
        return redirect("/main", code=302)
    if path.startswith("/api/") and not legacy_http_api_enabled():
        return error_response(
            "Legacy HTTP API is disabled. Use the MCP endpoint instead.",
            410,
            "legacy_http_api_disabled",
        )
    if auth_exempt_path(path):
        return None
    if path == "/api/sync/full" and internal_api_auth_ok():
        return None
    if request.method in {"POST", "PUT", "PATCH", "DELETE"} and path.startswith("/api/") and not browser_origin_ok():
        return jsonify({"error": "Invalid request origin."}), 403
    if authenticated():
        return None
    if wants_json_response():
        return jsonify({"error": "Authentication required."}), 401
    return redirect(url_for("login", next=request.full_path.rstrip("?")), code=302)


