    return jsonify({
        "name": "employee-analytics-context",
        "transport": "http-json-rpc",
        "endpoint": "/mcp",
        "auth": "shared-secret" if os.getenv("MCP_SHARED_SECRET", "").strip() else "none",
        "methods": ["initialize", "tools/list", "tools/call"],
    })


